(window.webpackJsonp=window.webpackJsonp||[]).push([[67],{539:function(t,e,n){"use strict";n.r(e);var r=n(0),o=Object(r.a)({},(function(){return this._self._c("ContentSlotsDistributor",{attrs:{"slot-key":this.$parent.slotKey}},[this._self._c("div",{domProps:{innerHTML:"<p>&lt;div class=&quot;custom-block tip&quot;&gt;&lt;p class=&quot;custom-block-title&quot;&gt;摘要&lt;/p&gt;\n在数字孪生项目中，3D 场景不仅仅是静态展示，更需要根据实时数据动态变化。本文介绍如何将传统 2D 大屏界面与 3D 可视化场景深度集成，实现数据驱动的 3D 场景状态变化，打通大屏监控与 3D 交互的闭环。\n&lt;/div&gt;</p>\n<h2>一、2D 大屏与 3D 场景的融合</h2>\n<p>传统大屏可视化以 2D 图表为主，但在机房运维场景中，纯 2D 大屏存在空间感不足的问题。我们的方案是 <strong>2D + 3D 混合布局</strong>：</p>\n<pre><code>┌──────────────────────────────────────────┐\n│  ┌─────────┐  ┌──────────────┐  ┌─────┐ │\n│  │ 设备统计  │  │              │  │告警  │ │\n│  │ 环形图   │  │   3D 场景    │  │列表  │ │\n│  ├─────────┤  │              │  │     │ │\n│  │ 温湿度   │  │              │  │     │ │\n│  │ 折线图   │  │              │  │     │ │\n│  ├─────────┤  │              │  ├─────┤ │\n│  │ 能耗     │  │              │  │网络  │ │\n│  │ 柱状图   │  └──────────────┘  │拓扑  │ │\n│  └─────────┘                     └─────┘ │\n│  ┌──────────────────────────────────────┐ │\n│  │          底部状态栏/时间轴            │ │\n│  └──────────────────────────────────────┘ │\n└──────────────────────────────────────────┘\n</code></pre>\n<h2>二、数据驱动架构</h2>\n<h3>数据流设计</h3>\n<pre><code class=\"language-javascript\">// 数据中心 - 统一管理所有数据源\nclass DataCenter {\n  constructor() {\n    this.listeners = new Map()\n    this.cache = new Map()\n    this.ws = null\n  }\n\n  connect(url) {\n    this.ws = new WebSocket(url)\n    this.ws.onmessage = (event) =&gt; {\n      const { type, data } = JSON.parse(event.data)\n      this.cache.set(type, data)\n      this.notify(type, data)\n    }\n  }\n\n  subscribe(type, callback) {\n    if (!this.listeners.has(type)) {\n      this.listeners.set(type, new Set())\n    }\n    this.listeners.get(type).add(callback)\n\n    // 立即推送缓存数据\n    if (this.cache.has(type)) {\n      callback(this.cache.get(type))\n    }\n  }\n\n  notify(type, data) {\n    const callbacks = this.listeners.get(type)\n    callbacks?.forEach(cb =&gt; cb(data))\n  }\n}\n</code></pre>\n<h3>场景状态映射</h3>\n<pre><code class=\"language-javascript\">const dataCenter = new DataCenter()\n\n// 设备状态 → 3D 模型颜色\ndataCenter.subscribe('deviceStatus', (devices) =&gt; {\n  devices.forEach(({ id, status, temperature }) =&gt; {\n    const mesh = sceneManager.getDeviceMesh(id)\n    if (!mesh) return\n\n    // 状态颜色映射\n    const colorMap = {\n      normal: new THREE.Color(0x00ff88),\n      warning: new THREE.Color(0xffaa00),\n      error: new THREE.Color(0xff3333),\n      offline: new THREE.Color(0x666666)\n    }\n    mesh.material.color.copy(colorMap[status])\n\n    // 温度 → 发光强度\n    mesh.material.emissive.setHex(0xff0000)\n    mesh.material.emissiveIntensity = Math.max(0, (temperature - 40) / 60)\n  })\n})\n\n// 告警数据 → 3D 告警动画\ndataCenter.subscribe('alarms', (alarms) =&gt; {\n  alarms.forEach((alarm) =&gt; {\n    const mesh = sceneManager.getDeviceMesh(alarm.deviceId)\n    if (!mesh) return\n\n    // 闪烁告警动画\n    triggerAlarmAnimation(mesh, alarm.level)\n  })\n})\n\n// 能耗数据 → 2D 图表更新\ndataCenter.subscribe('energy', (data) =&gt; {\n  energyChart.setOption({\n    series: [{ data: data.values }]\n  })\n})\n</code></pre>\n<h2>三、告警动画系统</h2>\n<pre><code class=\"language-javascript\">function triggerAlarmAnimation(mesh, level) {\n  const colors = {\n    critical: 0xff0000,\n    warning: 0xff8800,\n    info: 0x0088ff\n  }\n\n  const originalColor = mesh.material.color.clone()\n  const alarmColor = new THREE.Color(colors[level])\n\n  // 闪烁动画\n  const tween = gsap.to({}, {\n    duration: 0.5,\n    repeat: -1,\n    yoyo: true,\n    onUpdate: function() {\n      const progress = this.progress()\n      mesh.material.color.lerpColors(originalColor, alarmColor, progress)\n      mesh.material.emissiveIntensity = progress * 0.5\n    }\n  })\n\n  // 保存引用以便停止\n  mesh.userData.alarmTween = tween\n}\n\nfunction clearAlarm(mesh) {\n  mesh.userData.alarmTween?.kill()\n  mesh.material.color.copy(mesh.userData.originalColor)\n  mesh.material.emissiveIntensity = 0\n}\n</code></pre>\n<h2>四、2D 图表与 3D 场景联动</h2>\n<p>点击 2D 图表中的数据项时，3D 场景自动定位到对应设备：</p>\n<pre><code class=\"language-javascript\">// ECharts 图表点击事件\nenergyChart.on('click', (params) =&gt; {\n  const deviceId = params.data.deviceId\n  // 3D 场景定位\n  sceneManager.focusOnDevice(deviceId)\n})\n\n// 3D 场景设备点击事件\nsceneManager.on('deviceClick', (deviceId) =&gt; {\n  // 高亮 2D 图表中的对应数据\n  highlightChartItem(deviceId)\n  // 显示设备详情面板\n  showDevicePanel(deviceId)\n})\n</code></pre>\n<h2>五、自适应布局</h2>\n<p>大屏项目通常需要适配不同分辨率，我们使用 <code>scale</code> 方案：</p>\n<pre><code class=\"language-javascript\">function initScreenAdapter() {\n  const designWidth = 1920\n  const designHeight = 1080\n\n  function resize() {\n    const scaleX = window.innerWidth / designWidth\n    const scaleY = window.innerHeight / designHeight\n    const scale = Math.min(scaleX, scaleY)\n\n    document.getElementById('app').style.transform =\n      `scale(${scale}) translate(-50%, -50%)`\n  }\n\n  resize()\n  window.addEventListener('resize', resize)\n}\n</code></pre>\n<h2>六、总结</h2>\n<p>2D 大屏与 3D 可视化的深度融合，关键在于：</p>\n<ol>\n<li><strong>统一数据中心</strong>：所有数据源通过 DataCenter 统一分发</li>\n<li><strong>状态映射清晰</strong>：数据变化 → 视觉变化的映射关系明确</li>\n<li><strong>双向联动</strong>：2D 图表点击定位 3D 设备，3D 设备点击更新 2D 面板</li>\n<li><strong>动画表达</strong>：用动画传递告警等关键状态信息</li>\n</ol>\n"}})])}),[],!1,null,null,null);e.default=o.exports}}]);